    // Navigation shortcuts
    // ---------------------------------------------------------------------------

    fun onRerunOnboardingTapped() = viewModelScope.launch {
        appPreferences.onboardingComplete = false
        _events.send(SettingsEvent.NavigateToOnboarding)
    }

