                            enabled = draftExtraFrames < 10,
                            modifier = Modifier.size(40.dp),
                            contentPadding = PaddingValues(0.dp),
                        ) {
                            Text("+")
                        }
                    }
                }
            },
            confirmButton = {
                Button(
                    onClick = {
                        viewModel.onExtraFramesChanged(draftExtraFrames)
                        showExtraFramesDialog = false
                    },
                ) { Text("Save") }
            },
            dismissButton = {
                TextButton(onClick = { showExtraFramesDialog = false }) { Text("Cancel") }
            },
        )
    }

    // ── GPS precision dialog ───────────────────────────────────────────────
    if (showGpsPrecisionDialog) {
        SingleChoiceDialog(
            title = "GPS precision",
            options = listOf(
                GpsPrecision.HIGH to "High",
                GpsPrecision.BATTERY_SAVER to "Battery saver",
            ),
            current = state.gpsPrecision,
            onDismiss = { showGpsPrecisionDialog = false },
            onSelected = {
                viewModel.onGpsPrecisionChanged(it)
                showGpsPrecisionDialog = false
            },
        )
    }

    // ── Default export format dialog ───────────────────────────────────────
    if (showExportFormatDialog) {
        SingleChoiceDialog(
            title = "Default export format",
            options = listOf(
                ExportFormat.CSV to "CSV",
                ExportFormat.JSON to "JSON",
                ExportFormat.PLAIN_TEXT to "Plain text",
            ),
            current = state.defaultExportFormat,
            onDismiss = { showExportFormatDialog = false },
            onSelected = {
                viewModel.onDefaultExportFormatChanged(it)
