@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun SettingsScreen(navController: NavHostController) {
    val viewModel: SettingsViewModel = viewModel()
    val state by viewModel.state.collectAsStateWithLifecycle()
    val context = LocalContext.current
    val scope = rememberCoroutineScope()
    val snackbarHostState = remember { SnackbarHostState() }
    val versionName = remember {
        runCatching {
            context.packageManager.getPackageInfo(context.packageName, 0).versionName ?: "—"
        }.getOrDefault("—")
    }

    // ── Dialog visibility state ────────────────────────────────────────────
    var showExtraFramesDialog by remember { mutableStateOf(false) }
    var draftExtraFrames by remember { mutableIntStateOf(state.extraFramesPerRoll) }

    var showGpsPrecisionDialog by remember { mutableStateOf(false) }
    var showExportFormatDialog by remember { mutableStateOf(false) }
    var showThemeDialog by remember { mutableStateOf(false) }

    var pendingRestoreUri by remember { mutableStateOf<Uri?>(null) }
    var showRestoreConfirmDialog by remember { mutableStateOf(false) }
    var showRestartDialog by remember { mutableStateOf(false) }

    // ── File picker for backup restore ────────────────────────────────────
    val filePickerLauncher = rememberLauncherForActivityResult(
        ActivityResultContracts.GetContent(),
    ) { uri ->
        if (uri != null) {
            pendingRestoreUri = uri
            showRestoreConfirmDialog = true
        }
    }

    // ── Event handling ────────────────────────────────────────────────────
    LaunchedEffect(Unit) {
        viewModel.events.collect { event ->
            when (event) {
                is SettingsEvent.ShareBackupFile -> {
                    val file = File(event.filePath)
                    val uri = FileProvider.getUriForFile(
                        context,
                        "${context.packageName}.fileprovider",
                        file,
                    )
                    val shareIntent = Intent(Intent.ACTION_SEND).apply {
                        type = "application/octet-stream"
                        putExtra(Intent.EXTRA_STREAM, uri)
                        putExtra(Intent.EXTRA_SUBJECT, "FRAME//LOG backup")
                        addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION)
                    }
                    context.startActivity(Intent.createChooser(shareIntent, "Share backup file"))
                }

                is SettingsEvent.RestoreCompleteRestartRequired -> {
                    showRestartDialog = true
                }

                is SettingsEvent.OpenTipJar -> {
                    openUrl(context, TIP_JAR_URL)
                }

                is SettingsEvent.OpenOssLicenses -> {
                    // OSS Licenses screen requires the Play OSS Licenses Gradle plugin — TODO
                    snackbarHostState.showSnackbar("Open source licenses coming in a future update")
                }

                is SettingsEvent.NavigateToOnboarding -> {
                    // TODO: navigate to Welcome/onboarding screen once implemented
                    snackbarHostState.showSnackbar("Re-run onboarding — coming soon")
                }

                is SettingsEvent.NavigateToWidgetSetup -> {
                    // TODO: navigate to Widget Setup screen once implemented
                    snackbarHostState.showSnackbar("Widget setup instructions — coming soon")
                }

                is SettingsEvent.ShowErrorMessage -> {
                    snackbarHostState.showSnackbar(event.message)
                }

                is SettingsEvent.ShowInfoMessage -> {
                    snackbarHostState.showSnackbar(event.message)
                }
            }
        }
    }

    Scaffold(
        topBar = {
            TopAppBar(title = { Text("Settings") })
        },
        snackbarHost = { SnackbarHost(snackbarHostState) },
    ) { innerPadding ->
        LazyColumn(
            modifier = Modifier.padding(innerPadding),
