            item { HorizontalDivider() }

            // ── Appearance ─────────────────────────────────────────────────
            item { SettingsSectionHeader("APPEARANCE") }

            item {
                SettingsRow(
                    label = "App theme",
                    value = state.appTheme.label,
                    onClick = { showThemeDialog = true },
