@Composable
private fun FilterChipsRow(
    displayedFilters: List<Filter>,
    activeFilterIds: Set<Int>,
    hasMoreFilters: Boolean,
    filterEvSum: Float,
    filterHasNullEv: Boolean,
    activeCount: Int,
    onFilterToggled: (Int) -> Unit,
    onOpenPicker: () -> Unit,
